-- =============================================================
-- Talent Work Email Directory
-- PostgreSQL: CREATE TABLE + INSERT statements
-- Offshore and onshore contacts combined in one table
-- =============================================================

CREATE TABLE IF NOT EXISTS talent_directory (
    id               SERIAL PRIMARY KEY,
    first_name       VARCHAR(150)  NOT NULL,
    last_name        VARCHAR(150),
    designation      VARCHAR(255)  NOT NULL,
    department       VARCHAR(150)  NOT NULL,
    work_email       VARCHAR(255)  NOT NULL,
    location         VARCHAR(10)   NOT NULL CHECK (location IN ('offshore', 'onshore')),
    created_at       TIMESTAMP     NOT NULL DEFAULT NOW()
);

-- Optional: enforce unique emails
-- ALTER TABLE talent_directory ADD CONSTRAINT uq_talent_work_email UNIQUE (work_email);

