-- =============================================================
-- Recommended indexes
-- =============================================================

CREATE INDEX IF NOT EXISTS idx_talent_location   ON talent_directory (location);
CREATE INDEX IF NOT EXISTS idx_talent_department ON talent_directory (department);
CREATE INDEX IF NOT EXISTS idx_talent_email      ON talent_directory (work_email);
